import{_ as l,o as a,c as t,a4 as i}from"./chunks/framework.Bz0lZ1uX.js";const b=JSON.parse('{"title":"收藏功能说明","description":"","frontmatter":{},"headers":[],"relativePath":"guide/收藏功能.md","filePath":"guide/收藏功能.md","lastUpdated":null}'),r={name:"guide/收藏功能.md"},o=i('<h1 id="收藏功能说明" tabindex="-1">收藏功能说明 <a class="header-anchor" href="#收藏功能说明" aria-label="Permalink to &quot;收藏功能说明&quot;">​</a></h1><p>收藏功能帮助您管理常用素材，建立个人专属素材库，提高写作效率。</p><h2 id="收藏功能概述" tabindex="-1">收藏功能概述 <a class="header-anchor" href="#收藏功能概述" aria-label="Permalink to &quot;收藏功能概述&quot;">​</a></h2><p>收藏功能允许您：</p><ul><li>标记常用和高频使用的素材</li><li>按个人需求组织素材</li><li>快速调用收藏的素材</li><li>建立个人写作素材库</li></ul><h2 id="如何使用收藏" tabindex="-1">如何使用收藏 <a class="header-anchor" href="#如何使用收藏" aria-label="Permalink to &quot;如何使用收藏&quot;">​</a></h2><h3 id="添加收藏" tabindex="-1">添加收藏 <a class="header-anchor" href="#添加收藏" aria-label="Permalink to &quot;添加收藏&quot;">​</a></h3><ol><li><strong>浏览素材</strong>: 进入任意素材页面</li><li><strong>点击收藏</strong>: 找到收藏按钮（⭐图标）</li><li><strong>确认收藏</strong>: 点击后素材即被加入收藏列表</li></ol><h3 id="查看收藏" tabindex="-1">查看收藏 <a class="header-anchor" href="#查看收藏" aria-label="Permalink to &quot;查看收藏&quot;">​</a></h3><ol><li><strong>入口</strong>: 在侧边栏或顶部导航找到&quot;我的收藏&quot;</li><li><strong>浏览</strong>: 查看所有已收藏的素材</li><li><strong>筛选</strong>: 可按分类、标签筛选收藏内容</li></ol><h3 id="管理收藏" tabindex="-1">管理收藏 <a class="header-anchor" href="#管理收藏" aria-label="Permalink to &quot;管理收藏&quot;">​</a></h3><p><strong>分类管理</strong>:</p><ul><li>为收藏的素材添加自定义分类标签</li><li>按使用场景分组（如：开头素材、论证素材等）</li><li>创建个人专属分类体系</li></ul><p><strong>排序方式</strong>:</p><ul><li>按收藏时间排序（最新/最旧）</li><li>按使用频率排序（高频/低频）</li><li>按素材类型排序</li><li>自定义排序</li></ul><p><strong>批量操作</strong>:</p><ul><li>批量删除不需要的收藏</li><li>批量添加标签</li><li>批量移动到分类</li></ul><h2 id="收藏使用场景" tabindex="-1">收藏使用场景 <a class="header-anchor" href="#收藏使用场景" aria-label="Permalink to &quot;收藏使用场景&quot;">​</a></h2><h3 id="场景一-备考素材积累" tabindex="-1">场景一：备考素材积累 <a class="header-anchor" href="#场景一-备考素材积累" aria-label="Permalink to &quot;场景一：备考素材积累&quot;">​</a></h3><p><strong>操作步骤</strong>:</p><ol><li>浏览各类素材，将有价值的素材加入收藏</li><li>按主题分类（人物类、事件类、名言类等）</li><li>定期复习收藏的素材，加深记忆</li><li>模拟写作时直接调用收藏素材</li></ol><h3 id="场景二-写作快速调用" tabindex="-1">场景二：写作快速调用 <a class="header-anchor" href="#场景二-写作快速调用" aria-label="Permalink to &quot;场景二：写作快速调用&quot;">​</a></h3><p><strong>操作步骤</strong>:</p><ol><li>根据常用写作主题，预先收藏相关素材</li><li>写作时打开收藏列表，快速查找</li><li>按标签筛选，精准定位所需素材</li><li>复制素材内容到文章中使用</li></ol><h3 id="场景三-个人素材库建设" tabindex="-1">场景三：个人素材库建设 <a class="header-anchor" href="#场景三-个人素材库建设" aria-label="Permalink to &quot;场景三：个人素材库建设&quot;">​</a></h3><p><strong>操作步骤</strong>:</p><ol><li>持续收藏有价值的素材</li><li>建立个人分类体系</li><li>为素材添加个人笔记和心得</li><li>定期整理，保持素材库精简高效</li></ol><h2 id="收藏管理建议" tabindex="-1">收藏管理建议 <a class="header-anchor" href="#收藏管理建议" aria-label="Permalink to &quot;收藏管理建议&quot;">​</a></h2><h3 id="收藏数量" tabindex="-1">收藏数量 <a class="header-anchor" href="#收藏数量" aria-label="Permalink to &quot;收藏数量&quot;">​</a></h3><ul><li>建议收藏总数控制在50-100条</li><li>每个主题收藏3-5条素材</li><li>定期清理不再使用的收藏</li></ul><h3 id="分类建议" tabindex="-1">分类建议 <a class="header-anchor" href="#分类建议" aria-label="Permalink to &quot;分类建议&quot;">​</a></h3><p><strong>按素材类型分类</strong>:</p><ul><li>人物素材收藏</li><li>事件素材收藏</li><li>名言警句收藏</li><li>历史典故收藏</li></ul><p><strong>按使用场景分类</strong>:</p><ul><li>开头素材收藏</li><li>论证素材收藏</li><li>结尾素材收藏</li><li>过渡素材收藏</li></ul><p><strong>按高频主题分类</strong>:</p><ul><li>创新主题收藏</li><li>坚持主题收藏</li><li>责任主题收藏</li><li>梦想主题收藏</li></ul><h3 id="维护策略" tabindex="-1">维护策略 <a class="header-anchor" href="#维护策略" aria-label="Permalink to &quot;维护策略&quot;">​</a></h3><table><thead><tr><th>策略</th><th>操作</th><th>频率</th></tr></thead><tbody><tr><td>定期整理</td><td>删除不再需要的收藏</td><td>每月一次</td></tr><tr><td>补充更新</td><td>添加新发现的优质素材</td><td>每周一次</td></tr><tr><td>分类优化</td><td>调整分类体系</td><td>每季度一次</td></tr><tr><td>使用统计</td><td>查看哪些收藏最常用</td><td>不定期</td></tr></tbody></table><h2 id="收藏与搜索结合使用" tabindex="-1">收藏与搜索结合使用 <a class="header-anchor" href="#收藏与搜索结合使用" aria-label="Permalink to &quot;收藏与搜索结合使用&quot;">​</a></h2><h3 id="高效工作流" tabindex="-1">高效工作流 <a class="header-anchor" href="#高效工作流" aria-label="Permalink to &quot;高效工作流&quot;">​</a></h3><ol><li><strong>日常积累</strong>: 浏览素材库，收藏有价值的素材</li><li><strong>整理归类</strong>: 为收藏的素材添加标签和分类</li><li><strong>快速查找</strong>: 写作时在收藏中搜索需要的素材</li><li><strong>使用反馈</strong>: 标记常用素材，优化收藏结构</li></ol><h3 id="实用技巧" tabindex="-1">实用技巧 <a class="header-anchor" href="#实用技巧" aria-label="Permalink to &quot;实用技巧&quot;">​</a></h3><ul><li>搜索到好素材后第一时间收藏</li><li>收藏时添加个人备注和使用心得</li><li>定期查看&quot;高频使用&quot;收藏，重点记忆</li><li>结合作文题目，提前准备相关收藏</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q: 收藏数量有上限吗？</strong> A: 建议控制在100条以内，保持素材库精简高效。</p><p><strong>Q: 如何快速找到某个收藏？</strong> A: 使用收藏页面内的搜索功能，或按标签筛选。</p><p><strong>Q: 收藏会同步吗？</strong> A: 收藏数据保存在本地，建议定期备份重要素材。</p><p><strong>Q: 能否导出收藏？</strong> A: 可以将收藏内容复制保存到本地文档。</p>',49),e=[o];function n(h,s,d,u,c,g){return a(),t("div",null,e)}const q=l(r,[["render",n]]);export{b as __pageData,q as default};
